package com.yottastudios.ns.collabspace.workspace.manager.query.impl;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeTagEntity;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeTagQueryManager;
import com.yottastudios.ns.collabspace.workspace.ro.TagNodeQueryRo;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagRelService;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeTagService;
import com.yottastudios.ns.collabspace.workspace.transfer.SpaceNodeTransfer;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeTagVo;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.function.Function;
import java.util.stream.Collectors;

@Service
public class SpaceNodeTagQueryManagerImpl implements SpaceNodeTagQueryManager {

    @Resource
    private ISpaceNodeTagService spaceNodeTagService;

    @Resource
    private ISpaceNodeTagRelService spaceNodeTagRelService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private SpaceNodeTransfer spaceNodeTransfer;

    @Override
    public List<SpaceNodeTagVo> listTags(String spaceId, Long userId) {
        List<SpaceNodeTagEntity> tags = spaceNodeTagService.listBySpaceIdAndUserId(spaceId, userId);
        return tags.stream().map(this::toTagVo).toList();
    }

    @Override
    public IPage<SpaceNodeVo> queryNodesByTag(Long userId, TagNodeQueryRo ro) {
        List<Long> spaceNodeIds = spaceNodeTagRelService.listSpaceNodeIdsByTagIdAndUserId(ro.getTagId(), userId);
        if (spaceNodeIds.isEmpty()) {
            return new Page<>(ro.getPageNum(), ro.getPageSize(), 0);
        }

        int total = spaceNodeIds.size();
        int fromIndex = (ro.getPageNum() - 1) * ro.getPageSize();
        if (fromIndex >= total) {
            return new Page<>(ro.getPageNum(), ro.getPageSize(), total);
        }
        int toIndex = Math.min(fromIndex + ro.getPageSize(), total);
        List<Long> pagedIds = spaceNodeIds.subList(fromIndex, toIndex);

        List<SpaceNodeEntity> entities = spaceNodeService.listByIds(pagedIds);
        Map<Long, SpaceNodeEntity> entityMap = entities.stream()
                .collect(Collectors.toMap(SpaceNodeEntity::getId, Function.identity()));
        List<SpaceNodeEntity> sorted = pagedIds.stream()
                .map(entityMap::get)
                .filter(Objects::nonNull)
                .toList();

        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVoWithRole(sorted);
        Page<SpaceNodeVo> page = new Page<>(ro.getPageNum(), ro.getPageSize(), total);
        page.setRecords(vos);
        return page;
    }

    private SpaceNodeTagVo toTagVo(SpaceNodeTagEntity entity) {
        return SpaceNodeTagVo.builder()
                .id(entity.getId())
                .name(entity.getName())
                .color(entity.getColor())
                .sortOrder(entity.getSortOrder())
                .build();
    }
}
```

